async (params, browser) => {
  // Open Trello
  await browser.open('https://trello.com')

  // Let Trello load
  await browser.wait(2000)

  // Update card via Trello API
  const result = await browser.evaluate(`const params = new URLSearchParams(); const name = params.name; if (name) params.set('name', name); const desc = params.description; if (desc) params.set('desc', desc); const due = params.due_date; if (due === 'null') params.set('due', ''); else if (due) params.set('due', due); if ([...params].length === 0) return { success: false, message: 'No fields to update' }; const resp = await fetch('/1/cards/' + params.card_id + '?' + params.toString(), { method: 'PUT', credentials: 'same-origin' }); if (!resp.ok) { const err = await resp.text(); throw new Error('Update failed: ' + resp.status + ' ' + err); } const card = await resp.json(); return { success: true, id: card.id, name: card.name, url: card.shortUrl || card.url }`)

  return result
}
